import heapq

class Solution:
    def minimumCost(self, cost):
        heap = [-c for c in cost]
        heapq.heapify(heap)
        total = 0
        while heap:
            for _ in range(2):
                if heap:
                    total += -heapq.heappop(heap)
            if heap:
                heapq.heappop(heap)
        return total

